// Define the files to scan for overdue tasks.
const BUCKET = 'obsidian-vault';
const filesToScan = [
  { bucket: BUCKET, fileKey: 'Homelab/10_Active Projects/Active Personal/!!! MASTER TASK LIST.md', label: 'Master Task List' }
];

// Today in Central Time
const TZ = 'America/Chicago';
const now = new Date();
const fmt = (opts) => new Intl.DateTimeFormat('en-US', { timeZone: TZ, ...opts });
const y = parseInt(fmt({ year: 'numeric' }).format(now));
const m = fmt({ month: '2-digit' }).format(now);
const d = fmt({ day: '2-digit' }).format(now);
const todayStr = `${y}-${m}-${d}`;

return filesToScan.map(f => ({ json: { ...f, todayStr } }));

// Scan file content for overdue tasks
const meta = $('Define Files to Scan').item.json;
const todayStr = meta.todayStr;
const todayDate = new Date(todayStr + 'T00:00:00');

const binaryKey = Object.keys($input.item.binary || {})[0] || 'data';
const binaryData = $input.item.binary?.[binaryKey];
if (!binaryData?.data) {
  return [{ json: { overdueTasks: [], fileLabel: meta.label, error: 'Could not read file' } }];
}

const content = Buffer.from(binaryData.data, 'base64').toString('utf-8');

const taskPattern = /^\s*- \[ \]\s+(.+)$/gm;
const duePattern = /\[due::\s*(\d{4}-\d{2}-\d{2})\s*\]/;
const areaPattern = /\[area::\s*(\w+)\s*\]/;
const priorityPattern = /\[priority::\s*([A-C])\s*\]/i;

const overdueTasks = [];
let match;
taskPattern.lastIndex = 0;

while ((match = taskPattern.exec(content)) !== null) {
  const taskLine = match[1];
  const dueMatch = taskLine.match(duePattern);
  if (!dueMatch) continue;

  const dueDateStr = dueMatch[1];
  const dueDate = new Date(dueDateStr + 'T00:00:00');
  if (dueDate >= todayDate) continue;

  const areaMatch = taskLine.match(areaPattern);
  const priorityMatch = taskLine.match(priorityPattern);
  const daysOverdue = Math.floor((todayDate - dueDate) / 86400000);

  const cleanTitle = taskLine
    .replace(/\[area::[^\]]+\]/g, '')
    .replace(/\[priority::[^\]]+\]/g, '')
    .replace(/\[due::[^\]]+\]/g, '')
    .replace(/\s{2,}/g, ' ')
    .trim();

  const AREA_EMOJI = { faith:'🙏', family:'💒', business:'🚀', consulting:'💼', work:'🏥', health:'💪', home:'🏠', personal:'🤖' };
  const area = areaMatch ? areaMatch[1] : 'unknown';

  overdueTasks.push({
    title: cleanTitle,
    area,
    emoji: AREA_EMOJI[area] || '📌',
    priority: priorityMatch ? priorityMatch[1].toUpperCase() : 'none',
    due: dueDateStr,
    daysOverdue,
    sourceFile: meta.label
  });
}

overdueTasks.sort((a, b) => {
  const po = { A:0, B:1, C:2, none:3 };
  const pd = (po[a.priority] || 3) - (po[b.priority] || 3);
  return pd !== 0 ? pd : b.daysOverdue - a.daysOverdue;
});

return [{ json: { overdueTasks, fileLabel: meta.label, todayStr } }];

// Build HTML digest email for overdue tasks
const items = $input.all();
const todayStr = items[0]?.json.todayStr || new Date().toISOString().split('T')[0];

const allTasks = items.flatMap(i => i.json.overdueTasks || []);

allTasks.sort((a, b) => {
  const po = { A:0, B:1, C:2, none:3 };
  return (po[a.priority]||3) - (po[b.priority]||3) || b.daysOverdue - a.daysOverdue;
});

if (allTasks.length === 0) {
  const html = `<html><body style="font-family:system-ui;max-width:600px;margin:0 auto;padding:24px">
    <h1>✅ All Clear — ${todayStr}</h1>
    <p style="color:#4caf50;font-size:1.1em">No overdue tasks found. Great work staying on top of things!</p>
  </body></html>`;
  return [{ json: { subject: `✅ All Clear — No Overdue Tasks · ${todayStr}`, html, totalOverdue: 0 } }];
}

const byPriority = allTasks.reduce((acc, t) => { acc[t.priority] = (acc[t.priority]||0)+1; return acc; }, {});

const PRIORITY_COLOR = { A:'#ff6b6b', B:'#f5a623', C:'#4ecdc4', none:'#888' };

const taskRows = allTasks.map(t => `
  <tr style="border-bottom:1px solid #2a2a3e">
    <td style="padding:10px 8px">${t.emoji} ${t.title}</td>
    <td style="padding:10px 8px;text-align:center"><span style="background:${PRIORITY_COLOR[t.priority]||'#888'};color:#000;padding:2px 8px;border-radius:12px;font-weight:700">${t.priority}</span></td>
    <td style="padding:10px 8px;color:#f5a623">${t.due}</td>
    <td style="padding:10px 8px;color:#ff6b6b;font-weight:700">${t.daysOverdue}d</td>
    <td style="padding:10px 8px;color:#888;font-size:0.85em">${t.area}</td>
  </tr>`).join('');

const html = `<!DOCTYPE html><html><head><meta charset="utf-8"></head>
<body style="background:#13131f;color:#e0e0f0;font-family:system-ui,sans-serif;max-width:680px;margin:0 auto;padding:24px">
  <div style="background:linear-gradient(135deg,#ff6b6b,#ee0979);border-radius:16px;padding:28px 32px;margin-bottom:24px">
    <h1 style="margin:0;color:#fff">⚠️ Overdue Task Alert</h1>
    <p style="margin:8px 0 0;color:rgba(255,255,255,0.8)">${todayStr} &bull; ${allTasks.length} overdue item${allTasks.length!==1?'s':''}</p>
  </div>
  <div style="display:flex;gap:12px;margin-bottom:24px">
    ${['A','B','C'].filter(p=>byPriority[p]).map(p=>`
    <div style="flex:1;background:#1e1e2e;border-radius:12px;padding:16px;text-align:center">
      <div style="font-size:2em;font-weight:700;color:${PRIORITY_COLOR[p]}">${byPriority[p]}</div>
      <div style="color:#888">Priority ${p}</div>
    </div>`).join('')}
  </div>
  <table style="width:100%;border-collapse:collapse;background:#1e1e2e;border-radius:12px;overflow:hidden">
    <thead><tr style="background:#2a2a3e">
      <th style="padding:12px 8px;text-align:left">Task</th>
      <th style="padding:12px 8px">P</th>
      <th style="padding:12px 8px;text-align:left">Due</th>
      <th style="padding:12px 8px;text-align:left">Overdue</th>
      <th style="padding:12px 8px;text-align:left">Area</th>
    </tr></thead>
    <tbody>${taskRows}</tbody>
  </table>
  <p style="color:#555;margin-top:24px;font-size:0.85em">These tasks have passed their due date. Open Obsidian to update or complete them.</p>
</body></html>`;

return [{ json: { subject: `⚠️ ${allTasks.length} Overdue Task${allTasks.length!==1?'s':''} — ${byPriority.A||0} Priority A · ${todayStr}`, html, totalOverdue: allTasks.length } }];
